-- Mobile-focused SQLite dump derived from backend/database/db/db.sqlite
-- Scope: subset tabel domain yang dipakai folder mobile-fix.
-- Included tables:
-- users, personal_access_tokens, admin_profiles, teacher_profiles, student_profiles,
-- majors, classes, school_years, semesters, rooms, subjects, time_slots,
-- class_schedules, daily_schedules, schedule_items, qrcodes, attendances,
-- attendance_attachments, devices, settings, absence_requests,
-- student_leave_permissions, student_follow_ups
-- Excluded: migrations, sessions, cache, jobs, telescope, password resets, dan tabel infra Laravel lain.
/* WARNING: Script requires that SQLITE_DBCONFIG_DEFENSIVE be disabled */
PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "users" ("id" integer primary key autoincrement not null, "name" varchar not null, "username" varchar not null, "email" varchar, "password" varchar not null, "phone" varchar, "contact" varchar, "code" varchar, "user_type" varchar check ("user_type" in ('admin', 'teacher', 'student')) not null, "active" tinyint(1) not null default '1', "remember_token" varchar, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "personal_access_tokens" ("id" integer primary key autoincrement not null, "tokenable_type" varchar not null, "tokenable_id" integer not null, "name" text not null, "token" varchar not null, "abilities" text, "last_used_at" datetime, "expires_at" datetime, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "admin_profiles" ("id" integer primary key autoincrement not null, "user_id" integer not null, "type" varchar check ("type" in ('admin', 'waka', 'kepsek', 'karyawan', 'staf')) not null default 'admin', "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "class_schedules" ("id" integer primary key autoincrement not null, "class_id" integer not null, "semester" integer not null, "year" varchar not null, "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime, foreign key("class_id") references "classes"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "daily_schedules" ("id" integer primary key autoincrement not null, "class_schedule_id" integer not null, "day" varchar check ("day" in ('Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday', 'Sunday')) not null, "created_at" datetime, "updated_at" datetime, foreign key("class_schedule_id") references "class_schedules"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "schedule_items" ("id" integer primary key autoincrement not null, "daily_schedule_id" integer not null, "subject_id" integer, "teacher_id" integer not null, "start_time" time not null, "end_time" time not null, "room" varchar, "keterangan" varchar, "created_at" datetime, "updated_at" datetime, foreign key("daily_schedule_id") references "daily_schedules"("id") on delete cascade, foreign key("subject_id") references "subjects"("id") on delete set null, foreign key("teacher_id") references "teacher_profiles"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "student_profiles" ("id" integer primary key autoincrement not null, "user_id" integer not null, "nisn" varchar not null, "nis" varchar not null, "gender" varchar not null, "address" text not null, "created_at" datetime, "updated_at" datetime, "class_id" integer, "is_class_officer" tinyint(1) not null default '0', "parent_phone" varchar, foreign key("user_id") references users("id") on delete cascade on update no action, foreign key("class_id") references "classes"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "qrcodes" ("id" integer primary key autoincrement not null, "token" varchar not null, "status" varchar not null default ('available'), "created_at" datetime, "updated_at" datetime, "type" varchar check ("type" in ('student', 'teacher')) not null default 'student', "schedule_id" integer, "issued_by" integer, "expires_at" datetime, "is_active" tinyint(1) not null default '1', foreign key("schedule_id") references "schedule_items"("id") on delete set null, foreign key("issued_by") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "devices" ("id" integer primary key autoincrement not null, "user_id" integer not null, "identifier" varchar not null, "name" varchar, "platform" varchar, "last_used_at" datetime, "active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "school_years" ("id" integer primary key autoincrement not null, "name" varchar not null, "start_year" integer not null, "end_year" integer not null, "active" tinyint(1) not null default '0', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "semesters" ("id" integer primary key autoincrement not null, "name" varchar not null, "school_year_id" integer not null, "active" tinyint(1) not null default '0', "created_at" datetime, "updated_at" datetime, foreign key("school_year_id") references "school_years"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "rooms" ("id" integer primary key autoincrement not null, "name" varchar not null, "location" varchar, "capacity" integer, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "subjects" ("id" integer primary key autoincrement not null, "code" varchar not null, "name" varchar not null, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "time_slots" ("id" integer primary key autoincrement not null, "name" varchar not null, "start_time" time not null, "end_time" time not null, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "majors" ("id" integer primary key autoincrement not null, "code" varchar not null, "name" varchar not null, "category" varchar, "bidang" varchar, "created_at" datetime, "updated_at" datetime, "department" varchar, "program_keahlian" varchar, "bidang_keahlian" varchar);
CREATE TABLE IF NOT EXISTS "absence_requests" ("id" integer primary key autoincrement not null, "student_id" integer, "class_id" integer, "requested_by" integer, "type" varchar not null, "start_date" date not null, "end_date" date not null, "reason" text, "status" varchar not null default ('pending'), "approved_by" integer, "approved_at" datetime, "approver_signature" text, "created_at" datetime, "updated_at" datetime, "teacher_id" integer, "attachment_path" varchar, foreign key("approved_by") references users("id") on delete set null on update no action, foreign key("requested_by") references users("id") on delete set null on update no action, foreign key("class_id") references classes("id") on delete cascade on update no action, foreign key("student_id") references student_profiles("id") on delete cascade on update no action, foreign key("teacher_id") references "teacher_profiles"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "attendance_attachments" ("id" integer primary key autoincrement not null, "attendance_id" integer not null, "path" varchar not null, "original_name" varchar, "mime_type" varchar, "size" integer, "created_at" datetime, "updated_at" datetime, foreign key("attendance_id") references "attendances"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "attendances" ("id" integer primary key autoincrement not null, "date" date not null, "student_id" integer, "teacher_id" integer, "qrcode_id" integer, "reason" text, "reason_file" varchar, "created_at" datetime, "updated_at" datetime, "attendee_type" varchar not null, "status" varchar not null default ('present'), "checked_in_at" datetime, "schedule_id" integer, "source" varchar, "is_draft" tinyint(1) not null default '0', "draft_saved_at" datetime, "finalized_at" datetime, "manual_session_started_at" datetime, foreign key("qrcode_id") references qrcodes("id") on delete set null on update no action, foreign key("teacher_id") references teacher_profiles("id") on delete set null on update no action, foreign key("student_id") references student_profiles("id") on delete set null on update no action, foreign key("schedule_id") references schedule_items("id") on delete set null on update no action);
CREATE TABLE IF NOT EXISTS "settings" ("id" integer primary key autoincrement not null, "key" varchar not null, "value" text, "type" varchar not null default 'string', "group" varchar not null default 'general', "description" text, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "student_leave_permissions" ("id" integer primary key autoincrement not null, "student_id" integer not null, "class_id" integer not null, "granted_by" integer not null, "schedule_id" integer, "type" varchar check ("type" in ('izin_pulang', 'dispensasi', 'sakit', 'izin')) not null default 'izin_pulang', "date" date not null, "start_time" time not null, "end_time" time, "reason" text, "attachment_path" varchar, "status" varchar check ("status" in ('active', 'returned', 'expired', 'cancelled')) not null default 'active', "returned_at" datetime, "returned_by" integer, "is_full_day" tinyint(1) not null default '0', "created_at" datetime, "updated_at" datetime, foreign key("student_id") references "student_profiles"("id") on delete cascade, foreign key("class_id") references "classes"("id") on delete cascade, foreign key("granted_by") references "users"("id") on delete cascade, foreign key("schedule_id") references "schedule_items"("id") on delete set null, foreign key("returned_by") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "classes" ("id" integer primary key autoincrement not null, "grade" varchar not null, "label" varchar not null, "created_at" datetime, "updated_at" datetime, "major_id" integer, "schedule_image_path" varchar, "homeroom_teacher_id" integer, foreign key("major_id") references majors("id") on delete set null on update no action, foreign key("homeroom_teacher_id") references "teacher_profiles"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "teacher_profiles" ("id" integer primary key autoincrement not null, "user_id" integer not null, "nip" varchar not null, "created_at" datetime, "updated_at" datetime, "homeroom_class_id" integer, "subject" text, "schedule_image_path" varchar, "jabatan" text, "bidang" varchar, "konsentrasi_keahlian" varchar, "kode_guru" varchar, foreign key("homeroom_class_id") references classes("id") on delete set null on update no action, foreign key("user_id") references users("id") on delete cascade on update no action);
CREATE TABLE IF NOT EXISTS "student_follow_ups" ("id" integer primary key autoincrement not null, "student_id" integer not null, "teacher_id" integer not null, "note" text not null, "action" varchar, "date" date not null, "created_at" datetime, "updated_at" datetime, foreign key("student_id") references "users"("id") on delete cascade, foreign key("teacher_id") references "users"("id") on delete cascade);
COMMIT;
